# Hierarchical drift detection for 100+ features
import numpy as np
from scipy.stats import ks_2samp

class HierarchicalDriftDetector:
    def __init__(self, feature_groups):
        self.feature_groups = feature_groups  # dict: group_name -> [feature_names]
        self.alerts = []

    def psi(self, expected, actual, buckets=10):
        bin_edges = np.percentile(expected, np.linspace(0, 100, buckets + 1))
        e = np.histogram(expected, bin_edges)[0] + 1e-6
        a = np.histogram(actual, bin_edges)[0] + 1e-6
        e, a = e / e.sum(), a / a.sum()
        return np.sum((e - a) * np.log(e / a))

    def evaluate(self, expected_data, actual_data, timestamp):
        # Level 1: Aggregate PSI across all features
        all_psi = np.mean([
            self.psi(expected_data[f], actual_data[f])
            for f in expected_data.columns
        ])

        if all_psi < 0.2:
            return "OK"  # No shift — stop here, avoid alert fatigue

        # Level 2: Drill down by feature group
        for group, features in self.feature_groups.items():
            group_psi = np.mean([
                self.psi(expected_data[f], actual_data[f])
                for f in features
            ])
            if group_psi > 0.2:
                # Level 3: Per-feature KS test
                for f in features:
                    _, pval = ks_2samp(
                        expected_data[f].dropna(),
                        actual_data[f].dropna()
                    )
                    if pval < 0.01 / len(features):  # Bonferroni correction
                        self.alerts.append({
                            'timestamp': timestamp,
                            'group': group,
                            'feature': f,
                            'psi': self.psi(expected_data[f], actual_data[f]),
                            'ks_pvalue': pval
                        })

        return self.alerts
